		// NAT rebinds); an ordered failover endpoint list is meaningless for it, so
		// reject rather than silently ignore a mis-targeted config (Q18 is edge-side
		// only).
		if c.Role == RoleConcentrator && len(peer.Endpoints) != 0 {
